Hi All!

I'm unable to get even simple Verilog -> C++ translation result to work.
Consider simple edge detector module:
```<code class="verilog">
/* timing parameters */
`timescale 1ns / 100ps

/**	This module detects input signal edge.
 * \param clock Clock signal
 * \param reset Reset signal
 * \param in_en Input enable signal
 * \param in Input signal
 * \param[out] out Output signal
 */
module edge_det(
	clock,
	reset,
	in_en,
	in,
	out
);
	/* inputs */
	input	clock;		/**< Clock signal			*/
	input	reset;		/**< Reset signal			*/
	input	in_en;		/**< Input enabled signal	*/
	input	in;			/**< Input signal			*/

	/* outputs */
	output	out;		/**< Output signal			*/

	/* locals */
	reg		in_del;		/**< Delayed input			*/

	/* assignments */
	assign out = in_en && in && !in_del;

	/* delay input */
	always @(posedge clock or posedge reset) begin
		if(reset) begin
			in_del <= 1'b0;
		end else begin
			in_del <= in;
		end
	end
endmodule
</code>
```
After preprocessing by verilator write simple C++ testbench (taken from "here":http://rattus-pubis.blogspot.ru/2011/02/experimenting-with-verilator-counter.html):
```<code class="cplusplus">
#include "vour.h"
#include "verilated.h"
#include "verilated_vcd_c.h"

int main(int argc, char** argv)
{
	Verilated::commandArgs(argc, argv);

	// init top verilog instance
	vour* top = new vour();

	// init trace dump
	Verilated::traceEverOn(true);
	VerilatedVcdC* tfp = new VerilatedVcdC;

	top->trace(tfp, 99);
	tfp->open("edge_det.vcd");

	// initialize simulation inputs
	top->clock	= 1;
	top->reset	= 1;
	top->in_en	= 1;
	top->in		= 0;

	 // run simulation for 100 clock periods
	 for(int i = 0; i < 100; i++)
	{
		top->reset	= (i < 5);
		top->in		= (i > 10);

		for(int clk = 0; clk < 2; ++clk)
		{
			top->eval();
			tfp->dump((2 * i) + clk);

			top->clock = !top->clock;
 		}
	}
	tfp->close();
}
</code>
```
After running this testbench open edge_det.vcd in gtkwave:

!edge_det.png!

And the test result is completely wrong. So the question is where I've made a mistake?
